-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- 6. Принудительное единое юр.лицо для всех профилей тенанта
-- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
-- ON CONFLICT DO NOTHING в seed.sql мешает обновить уже залитые
-- значения 'ООО ТБ Северо-Запад' → 'ООО ТБ' (Анна и Сергей в СПб).
-- Этот UPDATE гарантирует одинаковый результат и для свежей БД,
-- и для уже задеплоенной — после правки seed.sql.

UPDATE employee_profiles
SET legal_entity = 'ООО ТБ'
WHERE tenant_id = '00000000-0000-4000-8000-000000000001'
  AND legal_entity <> 'ООО ТБ';
